// DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useCallback, useRef, useMemo } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}

function useComponent(props: Props) {
  const weatherIcon = useMemo(() => {
    const normalizedCondition = props.condition.toLowerCase();
    if (normalizedCondition.includes('rain')) return '🌧️';
    if (normalizedCondition.includes('cloud')) return '☁️';
    if (normalizedCondition.includes('snow')) return '❄️';
    if (normalizedCondition.includes('storm') || normalizedCondition.includes('thunder')) return '⛈️';
    if (normalizedCondition.includes('fog') || normalizedCondition.includes('mist')) return '🌫️';
    if (normalizedCondition.includes('wind')) return '💨';
    return '☀️';
  }, [props.condition]);
  return { weatherIcon };
}

export default function Component(props: Props) {
  return (
    <Container maxWidth="lg" padding={24}>
      <Card padding={24} radius="lg" shadow="md">
        <Stack gap={24}>
          <Stack gap={8}>
            <Text variant="overline" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              {props.city}
            </Text>
            <Row align="center" gap={16} wrap>
              <Heading level={2}>
                {props.temperature}°{props.unit}
              </Heading>
              <Text variant="bodyLarge" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                {state.weatherIcon} {props.condition}
              </Text>
            </Row>
          </Stack>

          <Row gap={16} wrap>
            <Card padding={16} radius="md" shadow="none">
              <Stack gap={4}>
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">Humidity</Text>
                <Text variant="bodyLarge" weight="semibold">{props.humidity}%</Text>
              </Stack>
            </Card>
            <Card padding={16} radius="md" shadow="none">
              <Stack gap={4}>
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">Wind speed</Text>
                <Text variant="bodyLarge" weight="semibold">{props.windSpeed}</Text>
              </Stack>
            </Card>
          </Row>

          <Divider margin={0} />

          <Stack gap={12}>
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">5-day forecast</Text>
            <Row gap={12} wrap>
              {props.forecast.map((item, index) => (
                <Card key={`${item.day ?? 'day'}-${index}`} padding={12} radius="md" shadow="none">
                  <Stack gap={8} align="center">
                    <Text variant="caption" weight="semibold">{item.day}</Text>
                    <Text is="span" variant="bodyLarge">{item.icon}</Text>
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      {item.high}°{props.unit} / {item.low}°{props.unit}
                    </Text>
                  </Stack>
                </Card>
              ))}
            </Row>
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}

// DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };

function useComponent(props: Props) {
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfaction, setSatisfaction] = useState<number>(0);
  const [features, setFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState('');
  const [step, setStep] = useState(1);
  const [nameTouched, setNameTouched] = useState(false);
  const [emailTouched, setEmailTouched] = useState(false);
  const [submitted, setSubmitted] = useState(false);
  const [submittedPayload, setSubmittedPayload] = useState<ActionSubmitPayload | null>(null);

  const isValidEmail = (value: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value);
  const nameError = nameTouched && !name.trim() ? 'Name is required' : '';
  const emailError = emailTouched && !email.trim() ? 'Email is required' : emailTouched && !isValidEmail(email) ? 'Enter a valid email address' : '';
  const step1Valid = Boolean(name.trim()) && isValidEmail(email);
  const step2Valid = satisfaction >= 1 && satisfaction <= 5;
  const step3Valid = true;
  const commentsClamped = comments.slice(0, 500);
  const step4Valid = commentsClamped.length <= 500;
  const canGoNext = (step === 1 && step1Valid) || (step === 2 && step2Valid) || (step === 3 && step3Valid) || (step === 4 && step4Valid);
  const totalSteps = 5;

  const toggleFeature = useCallback((feature: string) => {
    setFeatures((current) =>
      current.includes(feature) ? current.filter((item) => item !== feature) : [...current, feature]
    );
  }, []);

  const goNext = useCallback(() => {
    if (step === 1) {
      setNameTouched(true);
      setEmailTouched(true);
      if (!step1Valid) return;
    }
    if (step === 2 && !step2Valid) return;
    if (step === 4 && !step4Valid) return;
    setStep((current) => Math.min(totalSteps, current + 1));
  }, [step, step1Valid, step2Valid, step4Valid]);

  const goBack = useCallback(() => {
    setStep((current) => Math.max(1, current - 1));
  }, []);

  const submit = useCallback(() => {
    const payload: ActionSubmitPayload = {
      name: name.trim(),
      email: email.trim(),
      satisfaction,
      features,
      comments: commentsClamped,
    };
    setSubmitted(true);
    setSubmittedPayload(payload);
    return payload;
  }, [name, email, satisfaction, features, commentsClamped]);

  return {
    submit,
    submitted,
    submittedPayload,
    name, setName, email, setEmail, satisfaction, setSatisfaction, features, setFeatures, comments, setComments,
    step, setStep, nameTouched, setNameTouched, emailTouched, setEmailTouched,
    nameError, emailError, step1Valid, step2Valid, step3Valid, step4Valid, canGoNext,
    featureOptions: props.featureOptions, satisfactionLabels: props.satisfactionLabels,
    toggleFeature, goNext, goBack, totalSteps, commentsClamped,
  };
}


export default function Component(props: Props) {
  const state = useComponent(props);

  const currentStepLabel = state.step <= 4 ? `Step ${state.step} of 4` : 'Step 5 of 5';
  const progressValue = ((Math.min(state.step, 5) - 1) / 4) * 100;
  const reviewAnswers = [
    { label: 'Name', value: state.name.trim() || '—' },
    { label: 'Email', value: state.email.trim() || '—' },
    { label: 'Satisfaction', value: state.satisfaction > 0 ? String(state.satisfaction) : '—' },
    { label: 'Features', value: state.features.length ? state.features.join(', ') : 'None selected' },
    { label: 'Comments', value: state.commentsClamped || '—' },
  ];

  return (
    <Container maxWidth="lg" padding={24}>
      <MotionKeyframes />
      <Stack gap={24}>
        <Stack gap={8}>
          <Row align="center" justify="between">
            <Heading level={2}>Multi-step Survey</Heading>
            <Badge variant="primary">{currentStepLabel}</Badge>
          </Row>
          <Progress value={progressValue} max={100} showLabel />
        </Stack>

        <Card padding={24} shadow="md">
          {state.step === 1 && (
            <Stack gap={16}>
              <Heading level={3}>About you</Heading>
              <Input
                label="Name"
                value={state.name}
                onChange={(value) => {
                  state.setName(value);
                  if (!state.nameTouched) state.setNameTouched(true);
                }}
                onBlur={() => state.setNameTouched(true)}
                required
                error={state.nameError}
                placeholder="Enter your name"
              />
              <Input
                label="Email"
                type="email"
                value={state.email}
                onChange={(value) => {
                  state.setEmail(value);
                  if (!state.emailTouched) state.setEmailTouched(true);
                }}
                onBlur={() => state.setEmailTouched(true)}
                required
                error={state.emailError}
                placeholder="you@example.com"
              />
            </Stack>
          )}

          {state.step === 2 && (
            <Stack gap={16}>
              <Heading level={3}>How satisfied are you?</Heading>
              <RadioGroup
                label="Satisfaction rating"
                value={state.satisfaction > 0 ? String(state.satisfaction) : ''}
                onChange={(value) => state.setSatisfaction(Number(value))}
                options={state.satisfactionLabels.map((label, index) => ({
                  value: String(index + 1),
                  label,
                }))}
              />
            </Stack>
          )}

          {state.step === 3 && (
            <Stack gap={16}>
              <Heading level={3}>What features interest you?</Heading>
              <Stack gap={12}>
                {state.featureOptions.map((feature) => (
                  <Checkbox
                    key={feature}
                    label={feature}
                    checked={state.features.includes(feature)}
                    onChange={() => state.toggleFeature(feature)}
                  />
                ))}
              </Stack>
            </Stack>
          )}

          {state.step === 4 && (
            <Stack gap={16}>
              <Heading level={3}>Additional comments</Heading>
              <TextArea
                label="Comments"
                value={state.comments}
                onChange={state.setComments}
                placeholder="Share anything else you'd like us to know"
                maxLength={500}
                showCount
                helperText="Optional"
              />
            </Stack>
          )}

          {state.step === 5 && (
            <Stack gap={16}>
              <Heading level={3}>Review your answers</Heading>
              <Stack gap={12}>
                {reviewAnswers.map((item) => (
                  <Box key={item.label} padding={16} background="var(--ggui-color-surfaceVariant, #f4f4f5)" borderRadius={8}>
                    <Stack gap={4}>
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">{item.label}</Text>
                      <Text>{item.value}</Text>
                    </Stack>
                  </Box>
                ))}
              </Stack>
            </Stack>
          )}

          {state.submitted && state.submittedPayload && (
            <Alert variant="success" title="Submitted">
              Your response has been submitted successfully.
            </Alert>
          )}

          <Divider margin={24} />

          <Row align="center" justify="between">
            <Button variant="ghost" onClick={state.goBack} disabled={state.step === 1}>Back</Button>
            {state.step < 5 ? (
              <Button
                variant="primary"
                onClick={state.goNext}
                disabled={state.step === 1 ? !state.step1Valid : state.step === 2 ? !state.step2Valid : false}
              >
                Next
              </Button>
            ) : (
              <Button variant="primary" onClick={state.submit}>Submit</Button>
            )}
          </Row>
        </Card>
      </Stack>
    </Container>
  );
}

// DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';


// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column: string } };

// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };

function useComponent(props: Props) {
  const taskUpdate = useCallback((payload: ActionTaskUpdatePayload) => {
    void payload;
  }, []);

  const safeColumns = Array.isArray(props.columns) && props.columns.length > 0 ? props.columns : [
    { id: 'todo', name: 'To Do' },
    { id: 'in-progress', name: 'In Progress' },
    { id: 'done', name: 'Done' },
  ];
  const columnOrder = safeColumns
    .map((column, index) => ({
      id: typeof column.id === 'string' && column.id.trim() ? column.id : `column-${index}` ,
      name: typeof column.name === 'string' && column.name.trim() ? column.name : `Column ${index + 1}` ,
    }))
    .filter((column) => Boolean(column.id));
  const defaultColumnId = columnOrder[0]?.id || 'todo';

  const normalizeTask = useCallback((task: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }, index = 0) => ({
    id: typeof task.id === 'string' && task.id.trim() ? task.id : `task-${index + 1}` ,
    title: typeof task.title === 'string' && task.title.trim() ? task.title : 'Untitled task',
    priority: task.priority || 'medium',
    assignee: typeof task.assignee === 'string' ? task.assignee : '',
    column: typeof task.column === 'string' && task.column.trim() ? task.column : defaultColumnId,
    dueDate: typeof task.dueDate === 'string' ? task.dueDate : '',
  }), [defaultColumnId]);

  const [tasks, setTasks] = useState(() => Array.isArray(props.tasks) ? props.tasks.map((task, index) => normalizeTask(task, index)) : []);
  const [addingForColumn, setAddingForColumn] = useState<string | null>(null);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [editingTitle, setEditingTitle] = useState('');
  const [streamVersion, setStreamVersion] = useState(0);
  const [streamEvent, setStreamEvent] = useState<StreamTaskChanged | undefined>(undefined);

  const columnNameById = columnOrder.reduce<Record<string, string>>((acc, column) => {
    if (column.id) acc[column.id] = column.name;
    return acc;
  }, {});

  const upsertTask = useCallback((incoming: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }, action?: 'create' | 'move' | 'edit' | 'delete') => {
    const id = incoming.id || `stream-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
    setTasks((current) => {
      const existingIndex = current.findIndex((task) => task.id === id);
      const normalized = {
        id,
        title: incoming.title || 'Untitled task',
        priority: incoming.priority || 'medium',
        assignee: incoming.assignee || '',
        column: incoming.column || defaultColumnId,
        dueDate: incoming.dueDate || '',
      };
      if (action === 'delete') {
        return current.filter((task) => task.id !== id);
      }
      if (existingIndex >= 0) {
        const next = [...current];
        next[existingIndex] = { ...next[existingIndex], ...normalized };
        return next;
      }
      return [...current, normalized];
    });
  }, [defaultColumnId]);

  const handleMoveTask = useCallback((taskId: string, columnId: string) => {
    if (!columnId) return;
    setTasks((current) => current.map((task) => task.id === taskId ? { ...task, column: columnId } : task));
    taskUpdate({ action: 'move', taskId, data: { column: columnId } });
  }, [taskUpdate]);

  const handleSaveEdit = useCallback((taskId: string) => {
    const nextTitle = editingTitle.trim();
    const currentTask = tasks.find((task) => task.id === taskId);
    const resolvedTitle = nextTitle || currentTask?.title || 'Untitled task';
    const updatedTask = currentTask ? { ...currentTask, title: resolvedTitle } : undefined;
    setTasks((current) => current.map((task) => task.id === taskId ? { ...task, title: resolvedTitle } : task));
    if (updatedTask) {
      taskUpdate({
        action: 'edit',
        taskId,
        data: { column: updatedTask.column, title: updatedTask.title, priority: updatedTask.priority, assignee: updatedTask.assignee, dueDate: updatedTask.dueDate },
      });
    }
    setEditingTaskId(null);
    setEditingTitle('');
  }, [editingTitle, taskUpdate, tasks]);

  const handleCreateTask = useCallback((columnId: string) => {
    const title = newTaskTitle.trim();
    if (!title) return;
    const id = `task-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
    const task = { id, title, priority: newTaskPriority, assignee: '', column: columnId, dueDate: '' };
    setTasks((current) => [...current, task]);
    taskUpdate({ action: 'create', taskId: id, data: { column: columnId } });
    setNewTaskTitle('');
    setNewTaskPriority('medium');
    setAddingForColumn(null);
  }, [newTaskPriority, newTaskTitle, taskUpdate]);

  const beginAddTask = useCallback((columnId: string) => {
    setAddingForColumn(columnId);
    setNewTaskTitle('');
    setNewTaskPriority('medium');
  }, []);

  const cancelAddTask = useCallback(() => {
    setAddingForColumn(null);
    setNewTaskTitle('');
    setNewTaskPriority('medium');
  }, []);

  const beginEditTask = useCallback((taskId: string, title: string) => {
    setEditingTaskId(taskId);
    setEditingTitle(title);
  }, []);

  const applyStreamEvent = useCallback((event: StreamTaskChanged | undefined) => {
    if (!event?.task) return;
    const incoming = event.task;
    if (event.action === 'delete' && incoming.id) {
      setTasks((current) => current.filter((task) => task.id !== incoming.id));
      setStreamVersion((value) => value + 1);
      return;
    }
    upsertTask(incoming, event.action);
    setStreamVersion((value) => value + 1);
  }, [upsertTask]);

  React.useEffect(() => {
    if (streamEvent) {
      applyStreamEvent(streamEvent);
    }
  }, [applyStreamEvent, streamEvent]);

  return {
    taskUpdate,
    taskChanged: { latest: streamEvent, all: streamEvent ? [streamEvent] : [] },
    tasks,
    columnOrder,
    columnNameById,
    tasksByColumn: columnOrder.map((column) => ({
      ...column,
      tasks: tasks.filter((task) => task.column === column.id),
    })),
    totalTasks: tasks.length,
    completedCount: tasks.filter((task) => task.column === 'done').length,
    taskCounts: columnOrder.map((column) => ({ id: column.id, count: tasks.filter((task) => task.column === column.id).length })),
    addingForColumn,
    newTaskTitle,
    setNewTaskTitle,
    newTaskPriority,
    setNewTaskPriority,
    editingTaskId,
    editingTitle,
    setEditingTitle,
    streamVersion,
    handleMoveTask,
    handleCreateTask,
    handleSaveEdit,
    beginAddTask,
    cancelAddTask,
    beginEditTask,
    setStreamEvent,
    applyStreamEvent,
  };
}
}

export default function Component(props: Props) {
  const state = useComponent(props);

  React.useEffect(() => {
    if (typeof window === 'undefined') return;
    const handler = (event: Event) => {
      const customEvent = event as CustomEvent<StreamTaskChanged>;
      state.setStreamEvent(customEvent.detail);
    };
    window.addEventListener('ggui:agent-data', handler);
    return () => window.removeEventListener('ggui:agent-data', handler);
  }, [state]);

  React.useEffect(() => {
    state.applyStreamEvent(state.taskChanged.latest as StreamTaskChanged | undefined);
  }, [state.taskChanged.latest, state]);

  return (
    <Container maxWidth="full" padding={24}>
      <Stack gap={16}>
        <Card padding={16} radius="lg" shadow="sm">
          <Row justify="between" align="center" wrap>
            <Stack gap={4}>
              <Heading level={3}>Task Board</Heading>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Track tasks across columns and collaborate in real time.
              </Text>
            </Stack>
            <Row gap={12} align="center" wrap>
              <Badge variant="primary">Total {state.totalTasks}</Badge>
              <Badge variant="success">Done {state.completedCount}</Badge>
              <Badge variant="info">Updates {state.streamVersion}</Badge>
            </Row>
          </Row>
        </Card>

        <Row gap={16} align="stretch" wrap>
          {state.tasksByColumn.map((column) => (
            <Card key={column.id} padding={16} radius="lg" shadow="sm" border>
              <Stack gap={12}>
                <Row justify="between" align="center">
                  <Heading level={4}>{column.name}</Heading>
                  <Badge variant="secondary">{column.tasks.length}</Badge>
                </Row>

                <Stack gap={12}>
                  {column.tasks.map((task) => (
                    <Card key={task.id} padding={12} radius="md" shadow="none" border>
                      <Stack gap={12}>
                        <Row justify="between" align="start" gap={12} wrap>
                          <Stack gap={6}>
                            {state.editingTaskId === task.id ? (
                              <Input
                                label="Edit task title"
                                value={state.editingTitle}
                                onChange={state.setEditingTitle}
                                placeholder="Task title"
                              />
                            ) : (
                              <Text
                                variant="body"
                                weight="medium"
                                as={Clickable}
                                onClick={() => state.beginEditTask(task.id, task.title)}
                                onDoubleClick={() => state.beginEditTask(task.id, task.title)}
                              >
                                {task.title}
                              </Text>
                            )}
                            <Row gap={8} align="center" wrap>
                              <Badge
                                variant={task.priority === 'high' ? 'error' : task.priority === 'medium' ? 'warning' : 'success'}
                              >
                                {task.priority}
                              </Badge>
                              {task.dueDate ? (
                                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                                  Due {task.dueDate}
                                </Text>
                              ) : null}
                            </Row>
                          </Stack>
                          <Avatar name={task.assignee || 'Unassigned'} size="sm" />
                        </Row>

                        <Row justify="between" align="center" gap={8} wrap>
                          <Select
                            label="Move task"
                            value={task.column || column.id}
                            onChange={(nextColumn) => {
                              if (typeof nextColumn === 'string' && nextColumn) state.handleMoveTask(task.id, nextColumn);
                            }}
                            options={state.columnOrder.map((col) => ({ value: col.id, label: col.name }))}
                          />
                          <Row gap={8} align="center" wrap>
                            {state.editingTaskId === task.id ? (
                              <>
                                <Button variant="primary" size="sm" onClick={() => state.handleSaveEdit(task.id)}>Save</Button>
