// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  elements: Array<{ atomicNumber?: number; symbol?: string; name?: string; atomicWeight?: number; category?: string; row?: number; col?: number }>; // Full periodic table element data
}

function useComponent(props: Props) {
  const elements = Array.isArray(props.elements) ? props.elements : [];
  const [query, setQuery] = useState('');
  const [selectedSymbol, setSelectedSymbol] = useState<string>('');
  const [filterCategory, setFilterCategory] = useState<string>('all');
  const [showOnlySelectedCategory, setShowOnlySelectedCategory] = useState(false);
  const [hoveredCategory, setHoveredCategory] = useState<string>('');

  const normalizedElements = useMemo(() => {
    return elements.map((element) => ({
      ...element,
      category: element.category || 'unknown',
      name: element.name || '',
      symbol: element.symbol || '',
      atomicNumber: typeof element.atomicNumber === 'number' ? element.atomicNumber : undefined,
      atomicWeight: typeof element.atomicWeight === 'number' ? element.atomicWeight : undefined,
      row: typeof element.row === 'number' ? element.row : undefined,
      col: typeof element.col === 'number' ? element.col : undefined,
    }));
  }, [elements]);

  const categories = useMemo(() => {
    const seen = new Set<string>();
    normalizedElements.forEach((element) => {
      seen.add(element.category || 'unknown');
    });
    return Array.from(seen).sort();
  }, [normalizedElements]);

  const categoryColorMap = useMemo(() => {
    const fixed: Record<string, string> = {
      'alkali metal': 'var(--ggui-color-error-600, #dc2626)',
      'alkaline earth metal': 'var(--ggui-color-warning-600, #d97706)',
      'transition metal': 'var(--ggui-color-primary-600, #0284c7)',
      'post-transition metal': 'var(--ggui-color-primary-500, #0ea5e9)',
      metalloid: 'var(--ggui-color-info-600, #0284c7)',
      nonmetal: 'var(--ggui-color-success-600, #16a34a)',
      'reactive nonmetal': 'var(--ggui-color-success-500, #22c55e)',
      halogen: 'var(--ggui-color-warning-500, #d97706)',
      'noble gas': 'var(--ggui-color-primary-700, #0369a1)',
      lanthanide: 'var(--ggui-color-info-500, #0284c7)',
      actinide: 'var(--ggui-color-error-500, #dc2626)',
      unknown: 'var(--ggui-color-outline, #d4d4d8)',
    };
    return fixed;
  }, []);

  const getCategoryColor = useCallback((category?: string) => {
    return categoryColorMap[category || 'unknown'] || categoryColorMap.unknown;
  }, [categoryColorMap]);

  const filteredElements = useMemo(() => {
    const q = query.trim().toLowerCase();
    return normalizedElements.filter((element) => {
      const matchesQuery = !q || `${element.name} ${element.symbol}`.toLowerCase().includes(q);
      const matchesCategory = filterCategory === 'all' || element.category === filterCategory;
      const selectedElementCategory = normalizedElements.find((item) => item.symbol === selectedSymbol)?.category || '';
      const matchesSelectedCategory = !showOnlySelectedCategory || element.category === hoveredCategory || element.category === selectedElementCategory;
      return matchesQuery && matchesCategory && matchesSelectedCategory;
    });
  }, [normalizedElements, query, filterCategory, showOnlySelectedCategory, hoveredCategory, selectedSymbol]);

  const selectedElement = useMemo(() => {
    return normalizedElements.find((element) => element.symbol === selectedSymbol) || null;
  }, [normalizedElements, selectedSymbol]);

  const handleSelectElement = useCallback((symbol: string) => {
    const matched = normalizedElements.find((item) => item.symbol === symbol) || null;
    if (!matched) {
      return;
    }
    setSelectedSymbol(symbol);
    if (matched.category) {
      setHoveredCategory(matched.category);
    }
  }, [normalizedElements]);

  const selectedCategory = selectedElement?.category || 'unknown';
  const selectedCategoryColor = getCategoryColor(selectedCategory);

  return {
    query,
    setQuery,
    selectedSymbol,
    setSelectedSymbol,
    filterCategory,
    setFilterCategory,
    showOnlySelectedCategory,
    setShowOnlySelectedCategory,
    hoveredCategory,
    setHoveredCategory,
    categories,
    categoryColors: categoryColorMap,
    filteredElements,
    selectedElement,
    selectedCategory,
    selectedCategoryColor,
    handleSelectElement,
    getCategoryColor,
  };
}

