/** Action payload: Called when user clicks Add to Cart. Payload: { productId, quantity } */
type ActionAddToCartPayload = { productId: string; quantity: number };

function useComponent(props: Props) {
  const productData = props.product ?? {};
  const productId = productData.id ?? '';
  const productName = productData.name ?? 'Product';
  const price = typeof productData.price === 'number' ? productData.price : 0;
  const currency = productData.currency ?? 'USD';
  const rating = Math.max(0, Math.min(5, typeof productData.rating === 'number' ? productData.rating : 0));
  const reviewCount = typeof productData.reviewCount === 'number' ? productData.reviewCount : 0;
  const stock = Math.max(0, typeof productData.stock === 'number' ? productData.stock : 0);
  const description = productData.description ?? '';
  const specifications = Array.isArray(productData.specifications) ? productData.specifications : [];
  const reviews = Array.isArray(productData.reviews) ? productData.reviews : [];

  const [quantity, setQuantity] = useState(1);
  const [activeTab, setActiveTab] = useState('Description');

  const increaseQuantity = useCallback(() => {
    setQuantity((current) => Math.min(stock > 0 ? stock : 1, current + 1));
  }, [stock]);

  const decreaseQuantity = useCallback(() => {
    setQuantity((current) => Math.max(1, current - 1));
  }, []);

  const handleTabChange = useCallback((key: string) => {
    setActiveTab(key);
  }, []);

  const handleAddToCart = useCallback(() => {
    if (!productId || stock <= 0) {
      return;
    }
    return { productId, quantity };
  }, [productId, quantity, stock]);

  const formattedPrice = new Intl.NumberFormat(undefined, {
    style: 'currency',
    currency,
  }).format(price);

  const starIcons = Array.from({ length: 5 }, (_, index) => index < Math.round(rating));

  const stockLabel = stock <= 0 ? 'Out of Stock' : stock <= 5 ? 'Low Stock' : 'In Stock';
  const stockVariant = stock <= 0 ? 'error' : stock <= 5 ? 'warning' : 'success';

  return {
    productId,
    productName,
    price,
    currency,
    rating,
    reviewCount,
    stock,
    description,
    specifications,
    reviews,
    quantity,
    activeTab,
    formattedPrice,
    starIcons,
    stockLabel,
    stockVariant,
    increaseQuantity,
    decreaseQuantity,
    handleTabChange,
    handleAddToCart,
  };
}

