  const [typingState, setTypingState] = useState<{ sender: string; active: boolean }>({ sender: '', active: false });

  useEffect(() => {
    setLocalMessages(
      (props.messages || [])
        .filter((item): item is { sender: string; text: string; timestamp: string } => Boolean(item.sender && item.text && item.timestamp))
        .map((item) => ({ sender: item.sender, text: item.text, timestamp: item.timestamp })),
    );
  }, [props.messages]);

  useEffect(() => {
    const handleAgentData = (event: Event) => {
      const customEvent = event as CustomEvent<{ type?: string; data?: unknown }>;
      const eventType = customEvent.detail?.type;
      const payload = customEvent.detail?.data as StreamMessage | StreamTyping | undefined;

      if (!payload) return;

      if (eventType === 'message' && 'text' in payload && payload.sender && payload.text && payload.timestamp) {
        setStreamMessages((current) => {
          const exists = current.some(
            (item) => item.sender === payload.sender && item.text === payload.text && item.timestamp === payload.timestamp,
          );
          if (exists) return current;
          return [...current, { sender: payload.sender, text: payload.text, timestamp: payload.timestamp }];
        });
        return;
      }

      if (eventType === 'typing') {
        setTypingState({
          sender: payload.sender || '',
          active: Boolean((payload as StreamTyping).active),
        });
      }
    };

    window.addEventListener('ggui:agent-data', handleAgentData);
    return () => window.removeEventListener('ggui:agent-data', handleAgentData);
  }, []);

  const combinedMessages = React.useMemo(() => {
    const merged = [...localMessages, ...streamMessages];
    const deduped: Array<{ sender: string; text: string; timestamp: string }> = [];
    merged.forEach((item) => {
      const exists = deduped.some(
        (entry) => entry.sender === item.sender && entry.text === item.text && entry.timestamp === item.timestamp,
      );
      if (!exists) deduped.push(item);
    });
    return deduped;
  }, [localMessages, streamMessages]);

  const groupedMessages = React.useMemo(() => {
    const groups: Array<{ sender: string; messages: Array<{ sender: string; text: string; timestamp: string }> }> = [];
    combinedMessages.forEach((item) => {
      const last = groups[groups.length - 1];
      if (last && last.sender === item.sender) {
        last.messages.push(item);
      } else {
        groups.push({ sender: item.sender, messages: [item] });
      }
    });
    return groups;
  }, [combinedMessages]);

  const handleSend = useCallback(() => {
    const text = draft.trim();
    if (!text) return;
    const timestamp = new Date().toISOString();
    setLocalMessages((current) => [...current, { sender: props.currentUser, text, timestamp }]);
    setDraft('');
  }, [draft, props.currentUser]);

  const handleSubmit = useCallback((event: React.FormEvent) => {
    event.preventDefault();
    handleSend();
  }, [handleSend]);

  const handleKeyDown = useCallback((event: React.KeyboardEvent<HTMLInputElement>) => {
    if (event.key === 'Enter' && !event.shiftKey) {
      event.preventDefault();
      handleSend();
    }
  }, [handleSend]);

  const participantLabel = `${props.participantCount} participant${props.participantCount === 1 ? '' : 's'}`;
  const visibleTyping = Boolean(typingState.active && typingState.sender && typingState.sender !== props.currentUser);
  const typingSender = typingState.sender || 'Someone';

  return {
    draft,
    setDraft,
    handleSend,
    handleSubmit,
    handleKeyDown,
    groupedMessages,
    combinedMessages,
    visibleTyping,
    typingSender,
    participantLabel,
    currentUser: props.currentUser,
    title: props.title,
  };
}

