import React, { useState, useCallback, useEffect, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>; // Array of stocks with symbol, name, price, change, changePercent
}

// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: Updated price data for one or more stocks */
type StreamPriceUpdate = { symbol?: string; price?: number; change?: number; changePercent?: number };

/** Stream event: Market open/closed status update */
type StreamMarketStatus = { status?: 'open' | 'closed' | 'pre-market' | 'after-hours'; timestamp?: string };

function useComponent(props: Props) {
  const initialStocks = Array.isArray(props.stocks) ? props.stocks : [];
  const [stocks, setStocks] = useState(() => initialStocks.map((stock) => ({ ...stock })));
  const [lastUpdated, setLastUpdated] = useState(() => new Date());
  const [marketStatusValue, setMarketStatusValue] = useState<string>('');
  const [flashSymbols, setFlashSymbols] = useState<Record<string, number>>({});

  const formatPrice = useCallback((value?: number) => {
    const safeValue = typeof value === 'number' && Number.isFinite(value) ? value : 0;
    return safeValue.toFixed(2);
  }, []);

  const syncStocks = useCallback((incoming: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>) => {
    const safeIncoming = Array.isArray(incoming) ? incoming : [];
    setStocks(safeIncoming.map((stock) => ({ ...stock })));
    setLastUpdated(new Date());
  }, []);

  const applyPriceUpdate = useCallback((update?: StreamPriceUpdate) => {
    if (!update?.symbol) {
      return;
    }
    setStocks((current) => {
      const next = current.map((stock) => {
        if (stock.symbol !== update.symbol) {
          return stock;
        }
        return {
          ...stock,
          price: typeof update.price === 'number' ? update.price : stock.price,
          change: typeof update.change === 'number' ? update.change : stock.change,
          changePercent: typeof update.changePercent === 'number' ? update.changePercent : stock.changePercent,
        };
      });
      return next;
    });
    setFlashSymbols((current) => ({ ...current, [update.symbol]: Date.now() }));
    setLastUpdated(new Date());
  }, []);

  const applyMarketStatus = useCallback((status?: StreamMarketStatus) => {
    setMarketStatusValue(status?.status ? `${status.status}${status.timestamp ? ` • ${status.timestamp}` : ''}` : '');
  }, []);

  useEffect(() => {
    const safeStocks = Array.isArray(props.stocks) ? props.stocks : [];
    setStocks(safeStocks.map((stock) => ({ ...stock })));
    setLastUpdated(new Date());
  }, [props.stocks]);

  useEffect(() => {
    const handler = (event: Event) => {
      const customEvent = event as CustomEvent<{ type?: string; payload?: unknown } | unknown>;
      const detail = (customEvent && customEvent.detail) || {};
      const eventType = typeof detail === 'object' && detail && 'type' in detail ? (detail as { type?: string }).type : undefined;
      const payload = typeof detail === 'object' && detail && 'payload' in detail ? (detail as { payload?: unknown }).payload : detail;

      if (eventType === 'price-update') {
        applyPriceUpdate(payload as StreamPriceUpdate);
      } else if (eventType === 'market-status') {
        applyMarketStatus(payload as StreamMarketStatus);
      } else if (eventType === 'stocks') {
        const nextStocks = Array.isArray(payload)
          ? (payload as Props['stocks'])
          : (Array.isArray(props.stocks) ? props.stocks : []);
        syncStocks(nextStocks);
      }
      }
    };

    window.addEventListener('ggui:agent-data', handler);
    return () => window.removeEventListener('ggui:agent-data', handler);
  }, [applyMarketStatus, applyPriceUpdate, props.stocks, syncStocks]);

  useEffect(() => {
    const timer = window.setInterval(() => setLastUpdated(new Date()), 1000);
    return () => window.clearInterval(timer);
  }, []);

  const positiveCount = stocks.filter((stock) => (stock.change ?? 0) > 0).length;
  const negativeCount = stocks.filter((stock) => (stock.change ?? 0) < 0).length;

  return {
    stocks,
    lastUpdated,
    marketStatusValue,
    positiveCount,
    negativeCount,
    flashSymbols,
    formatPrice,
    syncStocks,
    applyPriceUpdate,
    applyMarketStatus,
  };
}

export default function Component(props: Props) {
  const state = useComponent(props);

  const getFlashAnimation = useCallback(() => {
    return 'ggui-fadeIn 200ms ease-out';
  }, []);

  return (
    <Container maxWidth="xl" padding={0}>
      <Stack gap={24}>
        <Header
          logo={<Heading level={2}>Market Watch</Heading>}
          actions={
