              <Text variant="bodySmall" weight="medium">{state.lastUpdated.toLocaleTimeString()}</Text>
            </Stack>
          }
          bordered
        />

        {state.marketStatusValue ? (
          <Alert variant="info" title="Market Status">
            {state.marketStatusValue}
          </Alert>
