              {state.stocks.map((stock, index) => {
                const isPositive = (stock.change ?? 0) >= 0;
                const borderColor = isPositive ? 'var(--ggui-color-success, #16a34a)' : 'var(--ggui-color-error, #dc2626)';
                const textColor = isPositive ? 'var(--ggui-color-success, #16a34a)' : 'var(--ggui-color-error, #dc2626)';
                const percent = typeof stock.changePercent === 'number' ? stock.changePercent : 0;
                const arrow = isPositive ? '▲' : '▼';
                const symbolKey = stock.symbol ?? `stock-${index}`;
