                      </Stack>

                      <Text size="2xl" weight="bold">${state.formatPrice(stock.price)}</Text>

                      <Stack gap={6}>
                        <Text variant="bodySmall" color={textColor}>
                          {arrow} {typeof stock.change === 'number' ? stock.change.toFixed(2) : '0.00'}
                        </Text>
