              <Stack gap={12}>
                <Row justify="between" align="center"><Text variant="label">Name</Text><Text>{state.name}</Text></Row>
                <Divider margin={0} />
                <Row justify="between" align="center"><Text variant="label">Email</Text><Text>{state.email}</Text></Row>
                <Divider margin={0} />
                <Row justify="between" align="center"><Text variant="label">Avatar</Text><Text>{state.avatar}</Text></Row>
                <Divider margin={0} />
                <Row justify="between" align="center"><Text variant="label">Role</Text><Text>{state.role}</Text></Row>
                <Divider margin={0} />
