              </Stack>
            </Card>
          </Stack>
        )}

        <Row justify="between" align="center">
          <Button variant="ghost" onClick={state.goBack} disabled={state.step === 1}>Go Back</Button>
          {state.step < 3 ? (
            <Button variant="primary" onClick={state.goNext} disabled={!state.canGoNext}>Next</Button>
          ) : (
            <Button variant="primary" onClick={state.handleComplete} disabled={!state.canComplete}>Complete Setup</Button>
          )}
        </Row>
        </Row>
      </Stack>
    </Card>
  </Container>
});
